screens.custom_css:
[selector='Bg-Container']{
  background-color: #F3F5F7;
  border-top:1px solid #D7DDE5 ;
  padding:30px 0px 30px 0px;
}
[selector='Content-1']{
  padding: 20px 50px 10px 50px;
  background-color: #FFFFFF;
}
[selector='Content-1'] .TitleText {
  color: #20242A;
  font-size: 24px;
  font-weight: 600;
  line-height: 32px;
}
[selector='Content-1'] .SubTitleText {
  color: #20242A;
  font-size: 14px;
  font-weight: 600;
  line-height: 20px;
}
[selector='Content-1'] .TitleText {
  color: #20242A;
  font-size: 24px;
  font-weight: 600;
  line-height: 32px;
}
[selector='Content-1'] .LabelText {
  color: #20242A;
  font-size: 12.5px;
  font-weight: 400;
  line-height: 18px;
}
[selector='Content-1'] img {
    vertical-align: middle;
    border-style: none;
    text-align: right;
    float: right;
}
/****Content-3***/
[selector='Content-3'] {
  padding: 30px 30px 30px 30px;
  background-color: #FFFFFF;
  border: 1px solid #D7DDE5;
  border-radius: 8px;
  min-height: 600px;
}
[selector='Content-3'] .Label{
  color: #596372;
  font-size: 12.5px;
  font-weight: 400;
  line-height: 18px;
}
[selector='Content-3'] .form-control {
    color: #20242A;
    border: 1px solid #D7DDE5;
    border-radius: 8px;
    padding: 20px 15px;
    font-size: 14px;
    font-weight: 400;
}
[selector='Content-3'] .multiselect .multiselect__tags{
    color: #20242A;
    border: 1px solid #D7DDE5;
    border-radius: 8px;
    font-size: 14px;
    font-weight: 400;
}
[selector='Content-3'] .form-group label {
    margin-top: 15px;
    color: #20242A;
    font-size: 14px;
    font-weight: 400;
    line-height: 20px;
}
[selector='Content-3'] .TitleText {
  color: #20242A;
  font-size: 24px;
  font-weight: 600;
  line-height: 32px;
}
[selector='Content-3'] .SubTitleText {
  color: #20242A;
