  font-weight: 600;
  line-height: 20px;
}
[selector='Content-3'] .TitleText {
  color: #20242A;
  font-size: 24px;
  font-weight: 600;
  line-height: 32px;
}
[selector='Content-3'] .LabelText {
  color: #20242A;
  font-size: 12.5px;
  font-weight: 400;
  line-height: 18px;
}
[selector='Footer'] {
    background-color: #20242A;
    min-height: 168px;
    max-height: 168px;
    text-align: center;
    display: flex;
    justify-content: center;
    align-items: center;
    height: 100vh;
    margin: 0;
}
[selector='Footer'] .Text1{
  color:#FFFFFF;
  font-size: 14px;
  font-weight: 500;
  line-height: 20px;
}
[selector='Footer'] .Text2{
  color:#FFFFFF;
  font-size: 14px;
  font-weight: 500;
  line-height: 20px;
  text-decoration: underline;
}
[selector='Footer'] .Text3{
  color:#FFFFFF;
